import React, { useState } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const Login = () => {
  const { login } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const from = location.state?.from?.pathname || "/";

  const [form, setForm] = useState({ email: "", password: "" });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [apiError, setApiError] = useState("");

  const validate = () => {
    const e = {};
    if (!form.email) e.email = "Email is required";
    else if (!/\S+@\S+\.\S+/.test(form.email)) e.email = "Invalid email format";
    if (!form.password) e.password = "Password is required";
    else if (form.password.length < 6) e.password = "Minimum 6 characters";
    return e;
  };

  const onChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: "" });
    setApiError("");
  };

  const onSubmit = async e => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setLoading(true);
    try {
      await login(form);
      navigate(from, { replace: true });
    } catch (err) {
      setApiError(err.response?.data?.message || "Login failed. Check your credentials.");
    } finally { setLoading(false); }
  };

  const inputStyle = (field) => ({
    background: "#1a1a2e",
    border: `1px solid ${errors[field] ? "#ff6584" : "#2a2a4a"}`,
    color: "#e8e8f0",
    borderRadius: 8
  });

  return (
    <div style={{ minHeight: "100vh", display: "flex" }}>
      {/* Left Panel */}
      <div className="d-none d-lg-flex flex-column justify-content-center p-5 flex-grow-1"
        style={{ background: "linear-gradient(135deg, #16213e 0%, #1a1a2e 100%)", borderRight: "1px solid #2a2a4a", maxWidth: "55%" }}>
        <Link to="/" className="d-flex align-items-center gap-2 fw-bold fs-5 mb-5 text-decoration-none">
          <span style={{ fontFamily: "JetBrains Mono, monospace", background: "rgba(108,99,255,0.15)", color: "#6c63ff", padding: "3px 10px", borderRadius: 6 }}>{"</>"}</span>
          <span style={{ color: "#e8e8f0" }}>CodeLearn</span>
        </Link>
        <h2 className="fw-bold mb-3" style={{ color: "#e8e8f0", fontSize: "2rem" }}>Welcome back, Developer!</h2>
        <p className="mb-4" style={{ color: "#9999bb", lineHeight: 1.7, maxWidth: 400 }}>
          Log in to continue your learning journey and pick up right where you left off.
        </p>
        <div className="d-flex flex-column gap-3">
          {["Access your enrolled courses", "Track your progress", "Continue from where you stopped"].map((f, i) => (
            <div key={i} className="d-flex align-items-center gap-2 p-3 rounded-3"
              style={{ background: "rgba(108,99,255,0.08)", borderLeft: "3px solid #6c63ff" }}>
              <i className="bi bi-check-circle-fill" style={{ color: "#43d9ad" }}></i>
              <span className="small" style={{ color: "#9999bb" }}>{f}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Right Panel - Form */}
      <div className="d-flex align-items-center justify-content-center flex-grow-1 p-4"
        style={{ background: "#0f0f1a", minWidth: 340 }}>
        <div style={{ width: "100%", maxWidth: 400 }}>
          <h1 className="fw-bold mb-2" style={{ color: "#e8e8f0" }}>Log In</h1>
          <p className="mb-4 small" style={{ color: "#9999bb" }}>
            Don't have an account? <Link to="/signup" style={{ color: "#6c63ff", fontWeight: 600 }}>Sign up free</Link>
          </p>

          {apiError && (
            <div className="alert mb-4 small" style={{ background: "rgba(255,101,132,0.1)", border: "1px solid #ff6584", color: "#ff6584", borderRadius: 10 }}>
              <i className="bi bi-exclamation-circle me-2"></i>{apiError}
            </div>
          )}

          <form onSubmit={onSubmit} noValidate>
            <div className="mb-3">
              <label className="form-label small fw-semibold" style={{ color: "#9999bb" }}>Email Address</label>
              <input type="email" name="email" className="form-control" placeholder="you@example.com"
                value={form.email} onChange={onChange} style={inputStyle("email")} />
              {errors.email && <div className="mt-1 small" style={{ color: "#ff6584" }}>{errors.email}</div>}
            </div>

            <div className="mb-4">
              <label className="form-label small fw-semibold" style={{ color: "#9999bb" }}>Password</label>
              <input type="password" name="password" className="form-control" placeholder="Min. 6 characters"
                value={form.password} onChange={onChange} style={inputStyle("password")} />
              {errors.password && <div className="mt-1 small" style={{ color: "#ff6584" }}>{errors.password}</div>}
            </div>

            <button type="submit" className="btn w-100 fw-bold py-3" disabled={loading}
              style={{ background: "#6c63ff", color: "white", border: "none", borderRadius: 10, fontSize: "1rem" }}>
              {loading ? <><span className="spinner-border spinner-border-sm me-2"></span>Logging in...</> : "Log In →"}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;
